@shawnbutts and anyone else who wants to get this to work while we wait: I've done a gross thing to make this work for me now. I really didn't want to fork this repo just to fix things. So I've resorted to monkey patching. This appears to work for me:

```python
def monkey_patch_service():
    import six
    import docker.api.service
    from docker import errors
    from docker.auth import auth
    import warnings

    def create_service(
            self, task_template, name=None, labels=None, mode=None,
            update_config=None, networks=None, endpoint_config=None,
            endpoint_spec=None
    ):
        if endpoint_config is not None:
            warnings.warn(
                'endpoint_config has been renamed to endpoint_spec.',
                DeprecationWarning
            )
            endpoint_spec = endpoint_config

        url = self._url('/services/create')
        headers = {}
        image = task_template.get('ContainerSpec', {}).get('Image', None)
        if image is None:
            raise errors.DockerException(
                'Missing mandatory Image key in ContainerSpec'
            )
        registry, repo_name = auth.resolve_repository_name(image)
        auth_header = auth.get_config_header(self, registry)
        if auth_header:
            headers['X-Registry-Auth'] = auth_header
        data = {
            'Name': name,
            'Labels': labels,
            'TaskTemplate': task_template,
            'Mode': mode,
            'UpdateConfig': update_config,
            'Networks': convert_service_networks(networks),
            'EndpointSpec': endpoint_spec
        }
        return self._result(
            self._post_json(url, data=data, headers=headers), True
        )

    def update_service(self, service, version, task_template=None, name=None,
                       labels=None, mode=None, update_config=None,
                       networks=None, endpoint_config=None,
                       endpoint_spec=None):

        if endpoint_config is not None:
            warnings.warn(
                'endpoint_config has been renamed to endpoint_spec.',
                DeprecationWarning
            )
            endpoint_spec = endpoint_config

        url = self._url('/services/{0}/update', service)
        data = {}
        headers = {}
        if name is not None:
            data['Name'] = name
        if labels is not None:
            data['Labels'] = labels
        if mode is not None:
            data['Mode'] = mode
        if task_template is not None:
            image = task_template.get('ContainerSpec', {}).get('Image', None)
            if image is not None:
                registry, repo_name = auth.resolve_repository_name(image)
                auth_header = auth.get_config_header(self, registry)
                if auth_header:
                    headers['X-Registry-Auth'] = auth_header
            data['TaskTemplate'] = task_template
        if update_config is not None:
            data['UpdateConfig'] = update_config
        if networks is not None:
            data['Networks'] = convert_service_networks(networks)
        if endpoint_spec is not None:
            data['EndpointSpec'] = endpoint_spec

        resp = self._post_json(
            url, data=data, params={'version': version}, headers=headers
        )
        self._raise_for_status(resp)
        return True

    def convert_service_networks(networks):
        if not networks:
            return networks
        if not isinstance(networks, list):
            raise TypeError('networks parameter must be a list.')

        result = []
        for n in networks:
            if isinstance(n, six.string_types):
                n = {'Target': n}
            result.append(n)
        return result

    docker.api.service.ServiceApiMixin.create_service = create_service
    docker.api.service.ServiceApiMixin.update_service = update_service
```

Just call the monkey_patch_service method and it should fix things for you.

We need to improve things on our end in terms of usability, but something like
```python
client.create_service(task_template, endpoint_config={
  'Ports': [
    { 'Protocol': 'tcp', 'PublishedPort': 8080, 'TargetPort': 80 },
  ]
})
```
should work, I think.

