def partial_but_seed(func, *args_partial, **kw_partial):
    def wrapped_func(seed):
        return func(seed=seed, *args_partial, **kw_partial)
    return wrapped_func

def seeds_map(seeds, mapper=map, collector=list):
    def real_wrapper(func):
        @functools.wraps(func)
        def _seeds_map(*args_map, **kw_map):
            if 'seed' in kw_map:
                print('del seed')
                kw_map = kw_map.copy()
                del kw_map['seed']

            rc = mapper(partial_but_seed(func, *args_map, **kw_map), seeds)

            return collector(rc)
