Can you provide an example. I tried this and I didn't have any problems:

```java
import jep.Jep;
import jep.JepException;

public class Test{

    private static int THREAD_COUNT = 32;

    private static int LOOP_COUNT = 1000;

    private static void invokeAlot(){
        try(Jep jep = new Jep(false)) {
            jep.eval("import time");
            StringBuilder function = new StringBuilder();
            function.append("def f(a):\n");
            // Sleep to make sure we stay in the invoke awhile
            function.append("  time.sleep(0.2)\n");
            function.append("  return a + 1\n");
            jep.eval(function.toString());
            Integer arg = 0;
            for(int i = 0 ; i < LOOP_COUNT ; i += 1){
                arg = (Integer) jep.invoke("f", arg);
            }
            // Just to make sure it did what I planned.
            System.out.println(arg.intValue() == LOOP_COUNT);
        }catch(JepException e){
            e.printStackTrace();
        }
    }

    public static void main(String[] args) throws InterruptedException{
        Thread[] t = new Thread[THREAD_COUNT];
        for(int i = 0 ; i < THREAD_COUNT ; i += 1){
            t[i] = new Thread(Test::invokeAlot);
            t[i].start();
        }
        for(int i = 0 ; i < THREAD_COUNT ; i += 1){
            t[i].join();
        }
    }

}
```
